const today = new Date().toLocaleDateString('ru-RU', {day:'numeric',month:'long',year:'numeric'});
const since = new Date(Date.now() - 24*3600*1000).toISOString().slice(0,16);
const sourcesList = SOURCES.slice(0, 120).join(', ');

const instruction = `Найди ХОРОШИЕ, ПОЗИТИВНЫЕ новости про Челябинск и Челябинскую область за последние 24 часа (с ${since}). Сегодня ${today}.

СДЕЛАЙ ЧЕРЕЗ web_search МИНИМУМ 5 РАЗЛИЧНЫХ ПОИСКОВЫХ ЗАПРОСОВ, чтобы покрыть не менее 100 источников. Примеры запросов:
- "Челябинск новости сегодня"
- "Челябинская область достижения"
- "site:74.ru Челябинск"
- "Челябинск открытие"
- "Челябинск культура"
- "Челябинск наука"
- "Челябинск спорт победа"
- "Челябинск благоустройство"
- "Челябинск бизнес открытие"
- "Челябинск экология"
- "ЮУрГУ", "ЧелГУ", "Трактор"

ПРИОРИТЕТНЫЕ ИСТОЧНИКИ (ищи прежде всего там): ${sourcesList}

ТЕМАТИКА — что собираем:
- Открытия объектов (парки, школы, больницы, магазины, производства)
- Достижения жителей (спорт, наука, культура, творчество, благотворительность)
- Культурные события (концерты, выставки, фестивали, премьеры)
- Научные успехи (университеты, разработки, гранты)
- Городские улучшения (благоустройство, дороги, транспорт, парки, ремонт)
- Бизнес-рост (новые производства, стартапы, инвестиции, экспорт)
- Экология (улучшения воздуха, высадка деревьев, очистка рек)
- Образование (открытие школ/садов, победы учеников)
- Социальные инициативы (волонтёры, помощь, семьи, здоровье)
- Спортивные победы (Трактор, Металлург, ФК Челябинск, индивидуальные спортсмены)
- Инфраструктура (аэропорт, метро-трамвай, дороги, мосты)
- Туризм и внутренние поездки по Южному Уралу

КАТЕГОРИЧЕСКИ ИСКЛЮЧАЙ:
- Криминал, убийства, грабежи, аварии ДТП, пожары, катастрофы
- ЧП, травмы, смерти, происшествия
- Коррупция, скандалы, аресты, уголовные дела
- Жалобы жителей, протесты, конфликты
- Политические споры, санкции, мобилизация
- Плохая погода как проблема (смог, снегопад-коллапс)
- Рост цен, экономические проблемы, увольнения

Для каждой значимой позитивной новости сделай дополнительный web_search чтобы собрать детали (что именно, когда, кто участвовал, цифры).

Верни СТРОГО JSON:
{
  "posts": [
    {
      "headline": "короткий заголовок до 80 символов",
      "category": "одна из: открытие / спорт / культура / наука / благоустройство / бизнес / экология / образование / соц.инициатива / туризм",
      "source_url": "ссылка на первоисточник",
      "source_name": "название издания",
      "summary": "2-3 предложения о том что произошло: факты, даты, имена, цифры",
      "why_good": "1 предложение почему это важная хорошая новость для жителей Челябинска"
    }
  ]
}

Количество постов: сколько нашлось хороших, 3-8 штук. Главное КАЧЕСТВО — только действительно значимые и позитивные. Если за сутки ничего достойного — {"posts": []}.`;

const body = JSON.stringify({
  model: 'grok-4-fast-reasoning',
  input: instruction,
  tools: [
    { type: 'web_search' },
    { type: 'x_search' }
  ]
});

return [{ json: { body } }];

const data = $input.first().json;
const output = data.output || [];

let jsonText = '';
for (const o of output) {
  if (o.type === 'message' && Array.isArray(o.content)) {
    for (const c of o.content) {
      if (c.type === 'output_text' && c.text) {
        jsonText = c.text;
        break;
      }
    }
  }
  if (jsonText) break;
}

if (!jsonText) return [];

jsonText = jsonText.replace(/```json\s*/g, '').replace(/```\s*$/g, '').trim();

let parsed;
try { parsed = JSON.parse(jsonText); } catch(e) { return []; }

const posts = parsed.posts || [];
if (!posts.length) return [];

function normalize(s) {
  return (s || '').toLowerCase()
    .replace(/[^a-zа-я0-9\s]/gi, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, 50);
}

const store = $getWorkflowStaticData('global');
if (!store.sentChelPosts) store.sentChelPosts = [];
const sentSet = new Set(store.sentChelPosts);

const seenInRun = new Set();
const fresh = [];
for (const p of posts) {
  if (!p.headline) continue;
  const key = normalize(p.headline);
  if (!key || key.length < 5) continue;
  if (sentSet.has(key) || seenInRun.has(key)) continue;
  seenInRun.add(key);
  fresh.push(p);
  store.sentChelPosts.push(key);
}

if (store.sentChelPosts.length > 500) store.sentChelPosts = store.sentChelPosts.slice(-500);

return fresh.map(p => ({ json: p }));

const res = $input.first().json;
let post = '';
if (res.content && Array.isArray(res.content)) {
  const textBlock = res.content.find(c => c.type === 'text');
  post = textBlock?.text?.trim() || '';
}
post = post.replace(/@che_v_che\s*$/i, '').trim();
post += '\n\n@che_v_che';
const id = 'chel_' + Date.now() + '_' + Math.random().toString(36).slice(2,7);
return [{ json: { post, id } }];
